class YTDLLogger:
    def debug(self, msg):
        if not msg.startswith('[debug] '):
            print(f"[YTDL] {msg}")

    def warning(self, msg):
        print(f"[YTDL WARNING] {msg}")

    def error(self, msg):
        print(f"[YTDL ERROR] {msg}")

