@bot.event
async def on_message(message):
    if not message.guild:
        return

    # Ignore our own messages to prevent them from inflating the scroll distance count
    if message.author.id == bot.user.id:
        return

    # Count messages for NP repost logic
    # We count ALL messages (users and bots) to determine "scroll distance"
    guild_id = message.guild.id
    
    if guild_id in guild_last_np_message:
        np_data = guild_last_np_message[guild_id]
        
        # Check if message is in the same channel as the NP message
        if message.channel.id == np_data['channel_id']:
            np_data['message_count'] += 1
            
            if np_data['message_count'] > 20:
                # Time to repost!
                
                # Check if we have a current song
                if guild_id in guild_current_song:
                    current_song = guild_current_song[guild_id]
                    
                    # Get volume (safely)
                    guild_id_str = str(guild_id)
                    default_volume = guild_settings.get(guild_id_str, {}).get("default_volume", 60) / 100.0
                    
                    # Re-send the message
                    vc = message.guild.voice_client
                    if vc and vc.is_connected():
                        view = SkipButton(guild_id, vc)
                        # Reset immediately to prevent concurrent duplicate posts
                        np_data['message_count'] = 0
                        # send_np_message handles deletion and updating global state
                        url = f"https://www.youtube.com/watch?v={current_song['id']}" if current_song.get('id') else current_song['url']
                        await send_np_message(guild_id, message.channel, current_song['title'], url, default_volume, view)

    # Process commands (but ignore bots)
    if message.author.bot:
        return

    await bot.process_commands(message)


@bot.event
async def on_voice_state_update(member, before, after):
    # If the bot itself moved or was kicked
    if member.id == bot.user.id:
        guild_id = member.guild.id
        
        # Bot was disconnected/kicked
        if after.channel is None:
            if guild_id in guild_queues:
                del guild_queues[guild_id]
            if guild_id in guild_current_song:
                del guild_current_song[guild_id]
            if guild_id in guild_last_np_message:
                del guild_last_np_message[guild_id]
            if guild_id in guild_skip_votes:
                del guild_skip_votes[guild_id]
                
            return

    # Check if a human left a channel where the bot is currently in
    if not member.bot and before.channel is not None:
        vc = member.guild.voice_client
        if vc and vc.is_connected() and before.channel.id == vc.channel.id:
            # Count humans remaining in the bot's channel
            humans_remaining = [m for m in vc.channel.members if not m.bot]
            if len(humans_remaining) == 0:
                # Start a task to check again in 30 seconds
                async def check_empty_and_leave():
                    await asyncio.sleep(30)
                    if vc and vc.is_connected():
                        humans_now = [m for m in vc.channel.members if not m.bot]
                        if len(humans_now) == 0:
                            guild_id = member.guild.id
                            if guild_id in guild_queues: del guild_queues[guild_id]
                            if guild_id in guild_current_song: del guild_current_song[guild_id]
                            await vc.disconnect()
                bot.loop.create_task(check_empty_and_leave())

    # Ignore bots for the auto-join logic
    if member.bot:
        return

    # Check if user joined a channel
    if after.channel is None:
        return

    # Check if we have a home channel set for this guild
    guild_id_str = str(member.guild.id)
    if guild_id_str not in guild_settings:
        return
        
    music_channel_id = guild_settings[guild_id_str].get("music_channel_id")
    if not music_channel_id:
        return

    # Check if the channel joined is the home channel
    if after.channel.id != music_channel_id:
        return

    # Check if the bot is already connected to a voice channel in this guild
    vc = member.guild.voice_client
    if vc and vc.is_connected():
        return # Already connected somewhere
        
    # Connect to the home channel
    try:
        await after.channel.connect()
        print(f"Auto-joined home channel: {after.channel.name} in {member.guild.name}")
    except Exception as e:
        print(f"Failed to auto-join home channel: {e}")


@bot.event
async def on_ready():
    load_settings()
    print(f"Logged in and ready as {bot.user.name}!")

